  <script>
    const THEME_KEY = 'qsh2-theme';
    const MODE_NAMES = { send: '直接发送', setinput: '仅输入', append: '追加输入' };
    const MODES = ['send', 'setinput', 'append'];
    let currentMode = 'send';
    let collapsed = false;

    // ── 主题 ──
    function applyTheme(theme) {
      document.documentElement.setAttribute('data-theme', theme);
      const btn = document.getElementById('btn-theme');
      btn.innerHTML = theme === 'dark'
        ? '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="5"/><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42"/></svg>'
        : '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"/></svg>';
    }

    function toggleTheme(e) {
      e.stopPropagation();
      const next = document.documentElement.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
      try { localStorage.setItem(THEME_KEY, next); } catch {}
      applyTheme(next);
    }

    // 监听状态栏主题变化
    window.addEventListener('storage', e => {
      if (e.key === THEME_KEY) applyTheme(e.newValue || 'light');
    });

    // ── 模式 ──
    function toggleMode(e) {
      e.stopPropagation();
      const idx = (MODES.indexOf(currentMode) + 1) % MODES.length;
      currentMode = MODES[idx];
      try { localStorage.setItem('qsh2-mode', currentMode); } catch {}
      document.getElementById('mode-badge').textContent = MODE_NAMES[currentMode];
    }

    // ── 折叠 ──
    function toggleCollapse(e) {
      e && e.stopPropagation();
      collapsed = !collapsed;
      const wrap = document.getElementById('grid-wrap');
      const chevron = document.getElementById('chevron');
      if (collapsed) {
        wrap.style.maxHeight = wrap.scrollHeight + 'px';
        requestAnimationFrame(() => {
          wrap.style.transition = 'max-height 0.32s cubic-bezier(0.55,0,1,0.45), opacity 0.25s ease';
          wrap.style.maxHeight = '0';
          wrap.style.opacity = '0';
        });
        chevron.classList.add('rotated');
      } else {
        wrap.style.transition = 'max-height 0.42s cubic-bezier(0.22,1,0.36,1), opacity 0.3s ease';
        wrap.style.maxHeight = wrap.scrollHeight + 'px';
        wrap.style.opacity = '1';
        chevron.classList.remove('rotated');
      }
    }

    document.getElementById('toolbar').addEventListener('click', () => toggleCollapse());

