    document.getElementById('options-grid').addEventListener('click', e => {
      const item = e.target.closest('.option-item');
      if (!item) return;
      const text = item.textContent.trim();
      if (!text || ['…','...'].includes(text)) return;

      if (typeof triggerSlash === 'function') {
        if (currentMode === 'send') triggerSlash(`/send ${text}|/trigger`);
        else if (currentMode === 'setinput') triggerSlash(`/setinput ${text}`);
        else {
          const cur = window.parent.$?.('#send_textarea').val() || '';
          triggerSlash(`/setinput ${cur ? cur + '\n' + text : text}`);
        }
      }

      // 自动收缩的代码已经去掉了，现在点击后面板会一直保持展开状态
    });


    // ── 初始化 ──
    setTimeout(() => {
      try {
        const theme = localStorage.getItem(THEME_KEY) || 'light';
        applyTheme(theme);
        const savedMode = localStorage.getItem('qsh2-mode') || 'send';
        currentMode = savedMode;
        document.getElementById('mode-badge').textContent = MODE_NAMES[currentMode];
      } catch {}

      try {
        const msg = getChatMessages(getCurrentMessageId())[0];
        const match = msg.message.match(/<options>((?:(?!<options>).)*?)<\/options>/s);
        const opts = (match ? match[1] : '').split('|').map(s => s.trim()).filter(Boolean);
        const grid = document.getElementById('options-grid');
        opts.forEach((opt, i) => {
          const el = document.createElement('div');
          el.className = 'option-item';
          el.textContent = opt;
          el.style.animationDelay = `${i * 0.05}s`;
          if (opt.length > 20) el.style.fontSize = '0.9rem';
          grid.appendChild(el);
        });
        // 单个选项占满整行
        if (opts.length % 2 !== 0) grid.lastElementChild.style.gridColumn = '1 / -1';
      } catch (err) {
        document.getElementById('options-grid').innerHTML = `<div class="error">加载失败: ${err.message}</div>`;
      }
    }, 0);
  </script>
